-- Enrichment marathon batch: re:Director, Reactive Resume, Readeck, Readflow, ReadMe, Readymag, Reaparr, Recruit CRM

-- ── re:Director ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$A free, open-source, self-hosted redirect management service for creating, filtering, and controlling domain-level HTTP redirects from a lightweight Docker dashboard.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$Independent open-source project (solo maintainer)$q$, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$re:Director Review 2026: Features, Pricing and Self-Hosted Redirect Management$q$, seo_title),
  seo_meta_description = COALESCE($q$See what re:Director offers for self-hosted redirect management, including features, Docker deployment, licensing and how it compares for teams managing domain redirects.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$re:Director is a free, open-source, self-hosted redirect management service designed for developers, marketers and site operators who need centralized control over domain-level HTTP redirects. Released under the Apache License 2.0, the project is maintained by developer Jens Knipper (GitHub handle JensKnipper) and hosted at github.com/re-Director/re-director, with documentation published at re-director.github.io. As of mid-2026 the repository has accumulated roughly 45 GitHub stars and 5 forks across 9 tagged releases, with the latest version, v0.0.10, published on June 8, 2026. The core promise of re:Director is simplicity: connect any domain, define where it should redirect to, and manage that redirect through a lightweight web dashboard, without needing a separate database or complex infrastructure. The backend is written in Java using the Spring Boot framework and built with Maven, requiring Java 25 to run directly, though most users deploy it as a Docker container pulled from Docker Hub under the jensknipper/re-director image, optionally orchestrated with Docker Compose for persistent storage. Inside the dashboard, users can create redirects tied to specific source and target domains, filter the redirect list by source, target or active status, and pause or resume individual redirects without deleting their configuration. re:Director supports all four common HTTP redirect status codes, 301 permanent, 302 temporary, 307 temporary method-preserving, and 308 permanent method-preserving, giving operators fine-grained control over how search engines and browsers treat each redirect. The interface is mobile-responsive and includes an automatic dark mode that follows system preferences. Because it has no formal pricing plans, company structure or sales team, re:Director is best understood as a developer tool rather than a commercial SaaS product: there is no free trial to speak of because the entire tool is free, and there is no enterprise tier because support is community-driven through GitHub issues and the project documentation. It targets the same audience as commercial link-redirect and domain-forwarding services, such as marketing teams consolidating expired campaign domains, agencies managing client rebrands, or engineering teams wanting an internal, self-hosted alternative to third-party redirect SaaS tools, but positions itself specifically around self-hosting, data ownership and avoiding vendor lock-in for something as fundamental as domain redirects.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ff286dd5-38ce-4dba-930e-50e4da2c4d62';

