-- ── Reactive Resume ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$A free, open-source, privacy-focused resume builder that lets anyone create, customize and export polished resumes without creating an account.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source (hosted or self-hosted)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$Independent open-source project$q$, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English plus community-translated languages via Crowdin$q$]::text[],
  seo_title = COALESCE($q$Reactive Resume Review 2026: Free Open-Source Resume Builder Guide$q$, seo_title),
  seo_meta_description = COALESCE($q$Explore Reactive Resume's features, templates, self-hosting options and pricing for this free, open-source, privacy-first resume builder at rxresu.me.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Reactive Resume is a free, open-source resume builder created by developer Amruth Pillai, with the project's public development traceable back to 2019 and its first major public release, version 2, launched in mid-2020. The tool is hosted at rxresu.me and its source code lives at github.com/AmruthPillai/Reactive-Resume, where it has grown into one of the most popular projects in its category with roughly 39.7 thousand GitHub stars and 4.5 thousand forks. It is distributed under the MIT license, meaning anyone can inspect, modify, self-host or redistribute the code freely. The product itself lets users pick from more than fifteen professionally designed templates, playfully named after Pokemon such as Azurill, Bronzor, Chikorita, Ditto, Gengar, Kakuna, Lapras, Onyx and Pikachu, fill in resume sections through a real-time editor with live preview, reorder sections via drag-and-drop, and export the finished document as a PDF, JSON or DOCX file. Basic use requires no account creation at all: a user can build and export a resume anonymously. For people who want to save and sync resumes across sessions, Reactive Resume supports account-based storage plus AI-assisted content suggestions through configurable integrations with OpenAI, Google Gemini and Anthropic Claude. The current architecture is built on TanStack Start (React 19 with Vite), Node.js and TypeScript on the backend, PostgreSQL with Drizzle ORM for data storage, ORPC for type-safe client-server communication, Better Auth for authentication (including passkey support), and Tailwind CSS with a Base UI component system for styling; state is managed with Zustand and TanStack Query. Anyone concerned about data privacy can self-host the entire stack via Docker, with PostgreSQL as the database and an optional SeaweedFS instance for S3-compatible file storage; as of version 5.1.0, PDF generation happens client-side in the browser rather than through an external print/rendering service, further reducing what data ever leaves the user's device. The interface supports multiple languages through community-driven translation on Crowdin, and the app includes a dark mode. Because there are no premium tiers, subscription fees or paywalled templates, Reactive Resume is positioned squarely as a free alternative to commercial resume builders like Novoresume, Zety or Canva's resume tools, appealing most to job seekers, students and privacy-conscious users who want full control over their resume data and are comfortable with, or actively prefer, an open-source, self-hostable tool.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '537f4377-d765-4451-9d22-d3ae543d7b4e';

