-- ── Readeck ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$A lightweight, self-hosted, open-source read-it-later and bookmark manager that saves clean, ad-free copies of articles, images and videos.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source (self-hosted); paid hosted tier planned$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$Independent open-source project$q$, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English, with additional community translations$q$]::text[],
  seo_title = COALESCE($q$Readeck Review 2026: Self-Hosted Open-Source Read-It-Later App$q$, seo_title),
  seo_meta_description = COALESCE($q$Learn what Readeck offers as a self-hosted, open-source alternative to Pocket, including features, licensing, mobile apps and pricing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Readeck is a self-hosted, open-source bookmark and read-it-later application that lets users save the readable content of web pages, images and videos so they can revisit them later in a clean, standardized, stripped-down layout free of ads and trackers. The project's primary source repository lives on Codeberg at codeberg.org/readeck/readeck rather than GitHub, reflecting its independent, community-driven development model, though a GitHub mirror exists and has attracted roughly 265 stars. Readeck is licensed under the GNU Affero General Public License version 3 (AGPLv3), which requires that any modified, network-deployed version of the code also make its source available, a common choice for self-hosted web applications that want to prevent proprietary forks. The core workflow mirrors better-known read-it-later services like Pocket or Wallabag: users save a link, typically via a browser extension or bookmarklet, and Readeck fetches and stores a clean, readable copy of that page's content, organizing it with tags, favorites and an archive state. Readeck also supports highlighting passages within saved articles so key excerpts can be found again quickly, following saved content via RSS and OPDS feeds for e-reader compatibility, and exporting saved articles to e-book formats for offline reading. The application ships as a single Docker container with no additional database service required, and reviewers note it can be set up in under an hour, with save-to-library actions completing in just a few seconds once configured. Companion mobile clients extend the ecosystem: an Android app is distributed on F-Droid and other Android app stores, built by a third-party developer as a client for the self-hosted Readeck service, and a native iOS app is available on the Apple App Store for iPhone and iPad users who want professional-grade bookmark management on mobile. As of mid-2026, Readeck remains a self-hosted-only product; there is no first-party hosted SaaS version, meaning every user runs their own instance, typically via Docker on a home server, NAS or VPS. According to the project's own roadmap, the team behind Readeck plans to introduce a paid, company-hosted tier sometime in 2026 for users who want a managed instance without operating their own server, which would represent Readeck's first commercial offering alongside its continued free, self-hosted, open-source core. The tool has been highlighted by several self-hosting and productivity outlets as one of the more polished, lightweight alternatives in the read-it-later category, particularly for users who have grown wary of the pricing changes or shutdowns affecting commercial bookmarking services.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '64003bd2-5181-45f3-8722-b827c604e9d2';

