-- ── Readflow ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$An open-source, self-hosted news-reading and read-it-later platform built on Go and React, with webhook integrations and offline export.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source (self-hosted)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$Independent open-source project$q$, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Readflow Review 2026: Open-Source Self-Hosted Read-It-Later Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Explore Readflow's features, integrations, licensing and self-hosting requirements for this open-source Go and React news-reading platform.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Readflow is an open-source, self-hosted news-reading and read-it-later platform created by developer Nicolas Carlier, with its GitHub repository at github.com/ncarlier/readflow first created in April 2019. The project is licensed under the GNU Affero General Public License version 3 (AGPLv3), with accompanying artwork released under Creative Commons terms. As of its most recent tagged release, v1.2.0 from March 4, 2024, the repository has accumulated roughly 474 GitHub stars, 34 forks and 682 commits, reflecting steady, focused development over several years rather than rapid commercial growth. Architecturally, Readflow's backend is written in Go, making up the majority of its codebase, paired with a TypeScript and React frontend and a GraphQL API for client-server communication; a PostgreSQL database is required for persistence. Self-hosters can deploy it several ways: compiling and running the Go binary directly, downloading pre-compiled binaries, or running it as a Docker container or via Docker Compose for a more turnkey setup. Functionally, Readflow centralizes article reading from multiple sources into one inbox-like interface, letting users save, organize and read content offline. Its standout feature is a flexible webhook system: incoming webhooks let external services push content into a user's Readflow queue (supporting sources like RSS feeds, Pocket, Wallabag and Shaarli), while outgoing webhooks let Readflow push saved or read articles out to other destinations, including S3-compatible storage buckets, enabling custom automation pipelines. Saved articles can be exported for offline reading in multiple formats, including HTML, PDF, EPUB and ZIP archives, and the application supports push notifications when new articles arrive. On the client side, Readflow is delivered as a Progressive Web App, giving it an app-like experience on both desktop and mobile without requiring a native app store listing, and it deliberately avoids ads and trackers to keep the reading experience clean. For power users and automation-minded self-hosters, the project also ships a companion CLI tool called readflow-ctl for scripting and bulk operations, plus a Model Context Protocol (MCP) server that allows AI assistants to interact with a user's Readflow instance programmatically. Because Readflow has no commercial entity behind it, hosted plan, or pricing tiers, it is entirely free to run, with the only cost being the infrastructure needed to host the Go backend, React frontend and PostgreSQL database, most commonly on a home server, NAS or small VPS alongside other self-hosted services in a typical self-hosting stack such as those cataloged on awesome-selfhosted lists.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6b8dd75e-cb27-4973-af45-0de6a657268d';

