-- ── ReadMe ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$An interactive API documentation platform that turns static developer docs into live, testable API reference hubs used by thousands of API-first companies.$q$, short_description),
  pricing_model = COALESCE($q$Freemium / tiered SaaS subscription$q$, pricing_model),
  starting_price = COALESCE($q$Free (Starter plan); paid plans from $250/month billed annually$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE($q$Approximately 70 to 80 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$ReadMe Review 2026: Interactive API Documentation Platform Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$See how ReadMe's interactive API documentation platform works, including pricing plans, key features, and how it compares for developer-facing docs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$ReadMe is an interactive API documentation platform founded by Gregory Koberger, with the company's origins dating to 2014 and its formal debut through Y Combinator's Winter 2015 batch in San Francisco, California, where it remains headquartered. The company has raised roughly $10 million in total funding, including a $1.2 million seed round in 2014 and a $9 million Series A led by Accel announced in August 2019, and today employs somewhere between 70 and 83 people according to various company-data aggregators, distributed across multiple continents in a largely remote-friendly setup. ReadMe's core product converts static developer documentation into interactive, customizable reference hubs where developers can execute live API calls, view real responses, and understand integration requirements directly inside the docs rather than switching to a separate API client. The platform is used by more than 4,000 companies, including large, well-known technology brands such as Microsoft and Akamai, spanning everything from early-stage startups to Fortune 500 enterprises that need to make their APIs approachable to third-party developers. Beyond interactive reference docs, ReadMe includes usage analytics that show which endpoints developers actually test, where they get stuck, and which documentation sections drive the most engagement, giving API product teams data to prioritize documentation improvements. As of its current pricing structure published directly on readme.com/pricing, ReadMe offers three tiers: a free Starter plan that includes a custom domain, bi-directional sync, the interactive API reference, usage metrics, a markdown editor, customizable themes and baseline AI features such as an AI dropdown, LLMs.txt support and an MCP server; a Pro plan priced at $250 per month on annual billing that adds team member invitations, branching and review workflows, notifications, private documentation, a landing page, changelog and forum modules, custom MDX components, reusable content blocks, custom CSS/HTML support, and expanded AI capabilities like Ask AI Lite, an AI writing agent called Owlbert, an AI linter, and a GitHub-based AI writer; and an Enterprise plan starting at $3,000 or more per month on annual contracts that adds multi-project management, removal of ReadMe branding, granular user roles and access controls, branch review permissions, a global reusable content library, audit logs, SSO and OAuth support, dedicated support and implementation services, plus enterprise-grade AI tooling such as documentation audits, private AI context and global lint rules. An optional Ask AI add-on is available across tiers for an additional $150 per month. This tiered structure positions ReadMe as a premium, feature-rich alternative to simpler documentation generators, aimed specifically at companies whose product is an API and whose developer experience directly affects adoption and revenue.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '889a35b0-763a-4ca4-86bc-b657c47e2c33';

