-- ── Reaparr ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$A free, open-source, self-hosted Plex downloader that pulls media from any accessible Plex server into your own library, also working as a Sonarr/Radarr indexer and download client.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source (donation-supported)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$Independent open-source project$q$, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English, French, German, Polish, with more in progress$q$]::text[],
  seo_title = COALESCE($q$Reaparr Review 2026: Open-Source Plex Downloader for Sonarr and Radarr$q$, seo_title),
  seo_meta_description = COALESCE($q$Learn what Reaparr does, how it integrates with Sonarr and Radarr, its features, licensing, self-hosting requirements and pricing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Reaparr is a free, open-source, self-hosted application described on its own website, reaparr.rocks, as a Plex downloader that brings content from any accessible Plex server to a user's own library. Its GitHub organization is Reaparr, with the primary repository at github.com/Reaparr/Reaparr, distributed under the GPL-3.0 open-source license. Notably, the project was not originally called Reaparr: it operated under a different, Plex-referencing name until it received a trademark complaint from Plex Inc., prompting a rename. The team settled on Reaparr, a deliberate play on the word Reaper with the extra arr appended to match the naming convention used by the well-known *arr ecosystem of self-hosted media tools such as Sonarr and Radarr, both to sidestep the trademark issue and to signal the project's role within that same tooling family going forward. Functionally, Reaparr connects to one or more Plex accounts and servers a user has access to and lets them browse, filter and download media from those libraries into their own collection, using dual viewing modes, a poster grid and a table layout, with filtering and sorting by attributes like genre, year and quality, plus the ability to choose a distinct destination folder for each downloaded item. Downloads are handled by multiple parallel threads so a large queue does not stall on a single slow transfer, and the application automatically recovers from interrupted downloads rather than requiring a manual restart. Beyond acting as a standalone downloader, Reaparr can also function as an indexer and download client inside Sonarr and Radarr, meaning users can add items to their Sonarr or Radarr queue and have Reaparr pick them up and process the download automatically, effectively substituting for a traditional torrent or Usenet indexer within that workflow. The application is distributed as Docker images published under the Reaparr organization on Docker Hub, and it is explicitly designed to run cross-platform on Windows, Linux and macOS, as well as on NAS-oriented platforms like Unraid and Synology, and on both ARM and AMD-based hardware. The interface currently supports English, French, German and Polish, with additional languages planned. Reaparr has no pricing tiers or company behind it; its documentation site describes it as free and open source, sustained through voluntary donations from users who want to support continued development, hosting costs and documentation upkeep, with an active Discord community providing user support alongside GitHub issues and the project's own changelog and FAQ pages.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'effcc65a-35ca-4139-bbe4-ff1e95fd6c80';

UPDATE tools SET logo = 'https://www.google.com/s2/favicons?domain=' || regexp_replace(regexp_replace(website, '^https?://', ''), '/.*$', '') || '&sz=256' WHERE id = 'effcc65a-35ca-4139-bbe4-ff1e95fd6c80' AND logo IS NULL AND website IS NOT NULL;

