-- ── Recruit CRM ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$An AI-powered applicant tracking system and CRM built specifically for recruitment and staffing agencies, used by firms across 80-plus countries.$q$, short_description),
  pricing_model = COALESCE($q$Tiered per-user SaaS subscription$q$, pricing_model),
  starting_price = COALESCE($q$$85/user/month (Pro plan, billed annually) or $100/user/month billed monthly$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE($q$Approximately 365 employees$q$, company_size),
  headquarters = COALESCE($q$Norwood, New Jersey, USA and Pune, India (dual headquarters, fully remote team)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Recruit CRM Review 2026: Pricing, Features and AI Recruiting Software Guide$q$, seo_title),
  seo_meta_description = COALESCE($q$See how Recruit CRM's applicant tracking system and CRM works for staffing agencies, including pricing plans, AI features and company background.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Recruit CRM is an applicant tracking system and CRM built specifically for recruitment agencies and executive search firms, founded in 2017 and now used by recruiting businesses across more than 80 countries. The company maintains dual headquarters, with a US entity registered in Norwood, New Jersey, and an operational hub in Pune, India, while running as a fully remote SaaS company with employees distributed across multiple continents; recent company-data sources put headcount at roughly 365 to 372 employees as of early 2026, and the company has publicly stated it has been growing at around 200 percent year over year, a figure that reflects the company's own marketing claims rather than independently audited figures. Recruit CRM positions itself as an AI-first platform purpose-built for the staffing and executive search workflow, distinguishing it from generic CRM or ATS software aimed at internal corporate recruiting teams. Its feature set spans the full agency recruiting lifecycle: a Chrome sourcing extension for pulling candidate data directly from LinkedIn and other sites, an AI resume parser that extracts structured candidate data automatically, GPT-based integration for tasks like writing job descriptions or candidate outreach, deal pipelines for tracking client business alongside candidate pipelines, a fully integrated mailbox, built-in phone calling and call recording, a reporting suite, unlimited open jobs, and direct job board posting. Pricing is structured in three tiers billed per user. The entry-level Pro plan starts at $85 per user per month when billed annually, or $100 per user per month on monthly billing, and includes the Chrome sourcing extension, AI resume parsing, GPT integration, unlimited email templates, an integrated mailbox, deal pipelines, phone calling and recording, a complete reporting suite, unlimited open jobs, job board posting, one hiring pipeline, up to two candidate matches and up to 15 custom fields. The Business plan, listed as the company's most popular tier, starts at roughly $125 per user per month annually (around $150 monthly) and adds automated email sequencing, bulk texting, an executive search report generator, resume formatting tools, custom roles and teams, multiple hiring pipelines, IP whitelisting, audit logs, single sign-on, additional email connections, up to 50 candidate matches, up to 150 custom fields, removal of Recruit CRM branding, and open API access. The top-tier Enterprise plan, priced from roughly $165 per user per month and requiring a custom demo for exact pricing, adds workflow automation with 1,000 included tasks per user per month, advanced analytics, LinkedIn messaging integration, phone and email data enrichment with 500 credits per user per month, calling and texting credits, an unlimited-jobs Recruit Craft module, job multiposting with 10 jobs per user per month included, and a dedicated account manager. A free trial is available across plans before committing to a paid subscription.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '16d7a916-ff92-4379-8cb9-06913256e22d';

