INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff286dd5-38ce-4dba-930e-50e4da2c4d62', $q$Custom domain redirects$q$, $q$Connect any domain and define exactly where it should redirect to, all managed from a central dashboard.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff286dd5-38ce-4dba-930e-50e4da2c4d62', $q$Selectable HTTP status codes$q$, $q$Choose between 301, 302, 307 or 308 responses so search engines and browsers treat each redirect correctly.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff286dd5-38ce-4dba-930e-50e4da2c4d62', $q$Filtering by source, target or status$q$, $q$Quickly locate a specific redirect in large lists by filtering on source domain, destination or active/paused state.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff286dd5-38ce-4dba-930e-50e4da2c4d62', $q$Pause and resume redirects$q$, $q$Temporarily disable a redirect without losing its configuration, then re-enable it later with one click.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff286dd5-38ce-4dba-930e-50e4da2c4d62', $q$No external database required$q$, $q$Runs as a single Docker container with no separate database dependency, simplifying deployment and backups.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff286dd5-38ce-4dba-930e-50e4da2c4d62', $q$Dark mode and responsive UI$q$, $q$The dashboard automatically follows system light/dark preferences and works on mobile as well as desktop.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff286dd5-38ce-4dba-930e-50e4da2c4d62', $q$Docker-first deployment$q$, $q$Ships as an official Docker Hub image with Docker Compose examples for persistent, reproducible deployments.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff286dd5-38ce-4dba-930e-50e4da2c4d62', $q$Apache 2.0 licensing$q$, $q$Fully open-source code that can be inspected, modified and redistributed without licensing fees.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff286dd5-38ce-4dba-930e-50e4da2c4d62', $q$Completely free with no pricing tiers or paywalls$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff286dd5-38ce-4dba-930e-50e4da2c4d62', $q$Simple, single-container Docker deployment with no database to manage$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff286dd5-38ce-4dba-930e-50e4da2c4d62', $q$Supports all major redirect status codes (301, 302, 307, 308)$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff286dd5-38ce-4dba-930e-50e4da2c4d62', $q$Open-source under Apache 2.0, so the code can be audited or modified$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff286dd5-38ce-4dba-930e-50e4da2c4d62', $q$Lightweight, focused feature set that avoids unnecessary complexity$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff286dd5-38ce-4dba-930e-50e4da2c4d62', $q$Maintained by a single developer, which is a bustus-factor risk for production reliance$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff286dd5-38ce-4dba-930e-50e4da2c4d62', $q$No official hosted/managed version, so self-hosting knowledge is required$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff286dd5-38ce-4dba-930e-50e4da2c4d62', $q$Small community (under 50 GitHub stars) means fewer third-party guides and integrations$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff286dd5-38ce-4dba-930e-50e4da2c4d62', $q$No built-in analytics or click-tracking for redirects$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff286dd5-38ce-4dba-930e-50e4da2c4d62', $q$No official SLA, support contract or enterprise tier for businesses that need guarantees$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff286dd5-38ce-4dba-930e-50e4da2c4d62', $q$Is re:Director free to use?$q$, $q$Yes. re:Director is fully free and open source under the Apache License 2.0, with no paid tiers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff286dd5-38ce-4dba-930e-50e4da2c4d62', $q$Do I need a database to run re:Director?$q$, $q$No. It is designed to run without an external database, simplifying deployment to a single Docker container.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff286dd5-38ce-4dba-930e-50e4da2c4d62', $q$Which HTTP redirect codes does re:Director support?$q$, $q$It supports 301, 302, 307 and 308 redirects, covering both permanent and temporary redirect scenarios.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff286dd5-38ce-4dba-930e-50e4da2c4d62', $q$Can I pause a redirect without deleting it?$q$, $q$Yes, redirects can be paused and resumed at any time while keeping their configuration intact.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff286dd5-38ce-4dba-930e-50e4da2c4d62', $q$Is there a hosted version of re:Director?$q$, $q$No official hosted version exists; the project is designed to be self-hosted via Docker on your own infrastructure.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff286dd5-38ce-4dba-930e-50e4da2c4d62', $q$Who maintains re:Director?$q$, $q$It is maintained by developer Jens Knipper and published on GitHub under the re-Director organization.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff286dd5-38ce-4dba-930e-50e4da2c4d62', $q$What technology is re:Director built with?$q$, $q$The backend is written in Java using Spring Boot and built with Maven; it is distributed as a Docker image.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff286dd5-38ce-4dba-930e-50e4da2c4d62', $q$Does re:Director support mobile devices?$q$, $q$Yes, the dashboard is responsive and usable on mobile browsers, and it also includes an automatic dark mode.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ff286dd5-38ce-4dba-930e-50e4da2c4d62', $q$Marketing domain consolidation$q$, $q$Redirect multiple expired campaign or landing-page domains to a current site without relying on a third-party redirect SaaS tool.$q$, $q$Marketing operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ff286dd5-38ce-4dba-930e-50e4da2c4d62', $q$Agency client rebrands$q$, $q$Manage redirects for client domain changes and rebrands from one self-hosted dashboard instead of per-registrar redirect settings.$q$, $q$Digital agencies and freelance developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ff286dd5-38ce-4dba-930e-50e4da2c4d62', $q$Internal engineering redirect service$q$, $q$Run a lightweight internal redirect layer for microsites, short links or legacy URLs without adding a new vendor dependency.$q$, $q$Engineering and DevOps teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ff286dd5-38ce-4dba-930e-50e4da2c4d62', $q$Self-Hosted$q$, $q$$0$q$, $q$Free forever (open source)$q$, NULL, $q$["Unlimited redirects","301/302/307/308 status code support","Docker-based deployment","Filtering, pause/resume controls","Community support via GitHub"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ff286dd5-38ce-4dba-930e-50e4da2c4d62', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$re:Director is a self-hosted, Dockerized redirect service that lets anyone connect a domain and define where traffic to it should go, without a database, license fee or vendor account. It is fully open source under the Apache License 2.0 and maintained by a single developer, Jens Knipper, with source code on GitHub and documentation at re-director.github.io.$q$, $q$The project is aimed at technically comfortable users, such as developers, sysadmins and marketing-ops teams, who want a lightweight internal alternative to commercial link-redirect SaaS tools while keeping full ownership of redirect data and infrastructure.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ff286dd5-38ce-4dba-930e-50e4da2c4d62', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core functionality centers on redirect creation and lifecycle management: users define a source domain and target URL, choose an HTTP status code (301, 302, 307 or 308), and the redirect is live immediately. Redirects can be filtered by source, target or status, and paused or resumed without deleting the configuration.$q$, $q$The tool ships as a Docker image (jensknipper/re-director) built on a Java/Spring Boot backend, requires no external database, and includes a responsive, dark-mode-aware web dashboard that works on both desktop and mobile.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ff286dd5-38ce-4dba-930e-50e4da2c4d62', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$re:Director has no pricing tiers because the entire tool is free and open source. Users self-host it on their own infrastructure (a VPS, home server or internal cluster), so the only ongoing cost is hosting and maintenance, not a license fee to the project itself.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ff286dd5-38ce-4dba-930e-50e4da2c4d62', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ff286dd5-38ce-4dba-930e-50e4da2c4d62', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('537f4377-d765-4451-9d22-d3ae543d7b4e', $q$15-plus professional templates$q$, $q$Choose from a wide range of professionally designed, ATS-friendly resume templates to start from.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('537f4377-d765-4451-9d22-d3ae543d7b4e', $q$No account required for basic use$q$, $q$Build and export a resume as a PDF without creating an account, preserving anonymity for casual users.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('537f4377-d765-4451-9d22-d3ae543d7b4e', $q$Real-time editor with live preview$q$, $q$See changes reflected instantly in a live preview pane while filling out resume sections.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('537f4377-d765-4451-9d22-d3ae543d7b4e', $q$Multiple export formats$q$, $q$Export finished resumes as PDF, JSON or DOCX, and generate a shareable public link.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('537f4377-d765-4451-9d22-d3ae543d7b4e', $q$AI-assisted content help$q$, $q$Optionally connect OpenAI, Google Gemini or Anthropic Claude API keys to get writing assistance on resume content.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('537f4377-d765-4451-9d22-d3ae543d7b4e', $q$Self-hosting via Docker$q$, $q$Deploy the entire application on private infrastructure using Docker and PostgreSQL for full data control.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('537f4377-d765-4451-9d22-d3ae543d7b4e', $q$Passkey authentication and dark mode$q$, $q$Sign in securely with passkeys and use the interface in a dark or light theme.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('537f4377-d765-4451-9d22-d3ae543d7b4e', $q$Community-translated interface$q$, $q$The UI is localized into multiple languages through community contributions on Crowdin.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('537f4377-d765-4451-9d22-d3ae543d7b4e', $q$Completely free with no premium tiers or paywalled templates$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('537f4377-d765-4451-9d22-d3ae543d7b4e', $q$Open-source (MIT license) with a large, active GitHub community$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('537f4377-d765-4451-9d22-d3ae543d7b4e', $q$No account required for basic resume creation and export$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('537f4377-d765-4451-9d22-d3ae543d7b4e', $q$Fully self-hostable for users who want complete data ownership$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('537f4377-d765-4451-9d22-d3ae543d7b4e', $q$Wide template selection and multiple export formats (PDF, JSON, DOCX)$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('537f4377-d765-4451-9d22-d3ae543d7b4e', $q$No official paid support plan or SLA for businesses or teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('537f4377-d765-4451-9d22-d3ae543d7b4e', $q$Self-hosting requires Docker and PostgreSQL knowledge for full control$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('537f4377-d765-4451-9d22-d3ae543d7b4e', $q$AI features depend on users supplying their own third-party API keys$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('537f4377-d765-4451-9d22-d3ae543d7b4e', $q$Not built for team or agency-scale resume/candidate management$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('537f4377-d765-4451-9d22-d3ae543d7b4e', $q$Community support only, since there is no dedicated commercial vendor$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('537f4377-d765-4451-9d22-d3ae543d7b4e', $q$Is Reactive Resume really free?$q$, $q$Yes, it is completely free and open source under the MIT license, whether used on rxresu.me or self-hosted.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('537f4377-d765-4451-9d22-d3ae543d7b4e', $q$Do I need to create an account to use Reactive Resume?$q$, $q$No, basic resume building and PDF export can be done without an account, preserving user privacy.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('537f4377-d765-4451-9d22-d3ae543d7b4e', $q$Can I self-host Reactive Resume?$q$, $q$Yes, the full application can be self-hosted via Docker with a PostgreSQL database and optional S3-compatible storage.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('537f4377-d765-4451-9d22-d3ae543d7b4e', $q$What export formats does Reactive Resume support?$q$, $q$Resumes can be exported as PDF, JSON or DOCX, and shared via a public link.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('537f4377-d765-4451-9d22-d3ae543d7b4e', $q$Does Reactive Resume use AI?$q$, $q$It can optionally integrate with OpenAI, Google Gemini or Anthropic Claude using your own API key for content assistance.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('537f4377-d765-4451-9d22-d3ae543d7b4e', $q$Who created Reactive Resume?$q$, $q$It was created by developer Amruth Pillai, with public development beginning in 2019.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('537f4377-d765-4451-9d22-d3ae543d7b4e', $q$What technology stack powers Reactive Resume?$q$, $q$It runs on TanStack Start (React 19/Vite), Node.js, TypeScript, PostgreSQL with Drizzle ORM, and Better Auth.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('537f4377-d765-4451-9d22-d3ae543d7b4e', $q$Is Reactive Resume available in multiple languages?$q$, $q$Yes, the interface is translated into multiple languages through community contributions on Crowdin.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('537f4377-d765-4451-9d22-d3ae543d7b4e', $q$Job seeker resume building$q$, $q$Quickly build and export an ATS-friendly resume from a template without paying for a subscription.$q$, $q$Individual job seekers and students$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('537f4377-d765-4451-9d22-d3ae543d7b4e', $q$Privacy-conscious self-hosting$q$, $q$Run a private instance of the resume builder so resume data never touches a third-party server.$q$, $q$Privacy-focused individuals and IT-savvy users$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('537f4377-d765-4451-9d22-d3ae543d7b4e', $q$Career centers and nonprofits$q$, $q$Offer a free, brandable resume-building tool to clients or students without licensing costs.$q$, $q$Career services, nonprofits and educators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('537f4377-d765-4451-9d22-d3ae543d7b4e', $q$Hosted (rxresu.me)$q$, $q$$0$q$, $q$Free forever$q$, NULL, $q$["15-plus resume templates","PDF, JSON and DOCX export","No account required for basic use","Optional AI content assistance","Public shareable resume links"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('537f4377-d765-4451-9d22-d3ae543d7b4e', $q$Self-Hosted$q$, $q$$0$q$, $q$Free forever (open source)$q$, NULL, $q$["Full control over data via your own infrastructure","Docker-based deployment with PostgreSQL","Optional SeaweedFS for S3-compatible storage","Same feature set as the hosted version","MIT-licensed source code"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('537f4377-d765-4451-9d22-d3ae543d7b4e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Reactive Resume is an open-source resume builder created by developer Amruth Pillai, with public development dating back to 2019 and a major version 2 relaunch in 2020. It is released under the MIT license and has grown to roughly 39.7 thousand GitHub stars, making it one of the most widely used open-source resume tools available.$q$, $q$The product is designed around privacy and portability: basic resume creation and export require no account, and the entire application can be self-hosted via Docker for users who want to keep their data fully under their own control.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('537f4377-d765-4451-9d22-d3ae543d7b4e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Users choose from 15-plus templates, edit content in a real-time editor with live preview and drag-and-drop section reordering, and export to PDF, JSON or DOCX. Optional AI assistance can be configured through OpenAI, Google Gemini or Anthropic Claude API keys to help refine resume content.$q$, $q$The stack is built on TanStack Start (React 19/Vite), PostgreSQL with Drizzle ORM, and Better Auth with passkey support; self-hosters run it via Docker with an optional SeaweedFS instance for S3-compatible storage, and translations are crowd-sourced via Crowdin.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('537f4377-d765-4451-9d22-d3ae543d7b4e', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Reactive Resume is completely free, whether used on the hosted rxresu.me instance or self-hosted on private infrastructure. There are no premium templates, subscription tiers or paywalls; the project is sustained by its open-source community rather than a commercial pricing model.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('537f4377-d765-4451-9d22-d3ae543d7b4e', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('537f4377-d765-4451-9d22-d3ae543d7b4e', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('64003bd2-5181-45f3-8722-b827c604e9d2', $q$Clean, ad-free reading view$q$, $q$Strips saved pages down to a standardized, readable layout free of ads, trackers and clutter.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('64003bd2-5181-45f3-8722-b827c604e9d2', $q$Tags, favorites and archive organization$q$, $q$Organize saved bookmarks using labels, favorite flags and an archive state to keep the library tidy.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('64003bd2-5181-45f3-8722-b827c604e9d2', $q$Highlighting$q$, $q$Highlight key passages within saved articles so important excerpts can be found again quickly.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('64003bd2-5181-45f3-8722-b827c604e9d2', $q$RSS and OPDS feed support$q$, $q$Follow your saved-article library through RSS, or connect it to e-readers via OPDS.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('64003bd2-5181-45f3-8722-b827c604e9d2', $q$E-book export$q$, $q$Export saved articles to e-book formats for offline reading on dedicated e-reader devices.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('64003bd2-5181-45f3-8722-b827c604e9d2', $q$Single-container Docker deployment$q$, $q$Runs as one Docker container with no separate database service required, simplifying self-hosting.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('64003bd2-5181-45f3-8722-b827c604e9d2', $q$Native mobile apps$q$, $q$A native iOS app and a community-built Android client provide mobile access to your Readeck library.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('64003bd2-5181-45f3-8722-b827c604e9d2', $q$REST API$q$, $q$A documented API lets developers integrate Readeck into their own tools and automation workflows.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('64003bd2-5181-45f3-8722-b827c604e9d2', $q$Free and open source under the AGPLv3 license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('64003bd2-5181-45f3-8722-b827c604e9d2', $q$Very easy to self-host, typically running as a single Docker container$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('64003bd2-5181-45f3-8722-b827c604e9d2', $q$Clean, ad-free and tracker-free reading experience$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('64003bd2-5181-45f3-8722-b827c604e9d2', $q$Native iOS app and a community Android client for mobile access$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('64003bd2-5181-45f3-8722-b827c604e9d2', $q$Supports highlights, tags, RSS and OPDS export for e-readers$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('64003bd2-5181-45f3-8722-b827c604e9d2', $q$No first-party hosted plan yet, so self-hosting is currently mandatory$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('64003bd2-5181-45f3-8722-b827c604e9d2', $q$Requires basic server administration skills such as Docker and reverse proxying$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('64003bd2-5181-45f3-8722-b827c604e9d2', $q$Smaller community and ecosystem compared to established tools like Pocket or Wallabag$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('64003bd2-5181-45f3-8722-b827c604e9d2', $q$Mobile apps are relatively new and less mature than the core web app$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('64003bd2-5181-45f3-8722-b827c604e9d2', $q$Upcoming paid hosted tier pricing has not yet been announced$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('64003bd2-5181-45f3-8722-b827c604e9d2', $q$Is Readeck free to use?$q$, $q$Yes, Readeck is free and open source under the AGPLv3 license; the only cost is hosting it yourself.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('64003bd2-5181-45f3-8722-b827c604e9d2', $q$Does Readeck offer a hosted version?$q$, $q$Not yet. As of mid-2026 Readeck is self-hosted only, though the project has announced plans for a paid, company-hosted tier in 2026.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('64003bd2-5181-45f3-8722-b827c604e9d2', $q$How do I install Readeck?$q$, $q$Readeck runs as a single Docker container with no separate database required, and can typically be set up in under an hour.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('64003bd2-5181-45f3-8722-b827c604e9d2', $q$Does Readeck have mobile apps?$q$, $q$Yes, there is a native iOS app on the App Store and a community-built Android client distributed via F-Droid.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('64003bd2-5181-45f3-8722-b827c604e9d2', $q$Can I export my saved articles?$q$, $q$Yes, Readeck supports exporting saved content to e-book formats and exposes libraries via RSS and OPDS feeds.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('64003bd2-5181-45f3-8722-b827c604e9d2', $q$What license does Readeck use?$q$, $q$Readeck is distributed under the GNU Affero General Public License version 3 (AGPLv3).$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('64003bd2-5181-45f3-8722-b827c604e9d2', $q$Where is Readeck's source code hosted?$q$, $q$Primarily on Codeberg at codeberg.org/readeck/readeck, with a mirror also available on GitHub.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('64003bd2-5181-45f3-8722-b827c604e9d2', $q$How is Readeck different from Pocket or Wallabag?$q$, $q$Readeck focuses on being lightweight and easy to self-host, with a single-container Docker setup, native mobile apps and highlight support built in.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('64003bd2-5181-45f3-8722-b827c604e9d2', $q$Personal read-it-later library$q$, $q$Save articles from around the web to read later in a clean, distraction-free format on any device.$q$, $q$Individual readers and researchers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('64003bd2-5181-45f3-8722-b827c604e9d2', $q$Privacy-focused bookmarking$q$, $q$Run a private, self-hosted bookmark manager that keeps saved content off third-party servers entirely.$q$, $q$Privacy-conscious self-hosters$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('64003bd2-5181-45f3-8722-b827c604e9d2', $q$Research and highlight collection$q$, $q$Save reference articles and highlight key passages to build a searchable personal knowledge archive.$q$, $q$Students, writers and researchers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('64003bd2-5181-45f3-8722-b827c604e9d2', $q$Self-Hosted$q$, $q$$0$q$, $q$Free forever (open source)$q$, NULL, $q$["Unlimited bookmarks, tags and highlights","RSS and OPDS feed support","E-book export","Native iOS app and community Android client","REST API access"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('64003bd2-5181-45f3-8722-b827c604e9d2', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Readeck is an open-source, self-hosted read-it-later and bookmark manager that saves clean, readable copies of web articles, images and videos so users can revisit them without ads, trackers or the risk of link rot. Development happens primarily on Codeberg rather than GitHub, and the project is licensed under AGPLv3.$q$, $q$It positions itself as a lightweight, easy-to-run alternative to services like Pocket or Wallabag, deployable as a single Docker container with no separate database dependency, and is aimed at privacy-conscious users comfortable running their own server.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('64003bd2-5181-45f3-8722-b827c604e9d2', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Saved content can be organized with tags, marked as favorites, or moved to an archive, and users can highlight important passages for later reference. Readeck exposes saved content via RSS and OPDS feeds and supports exporting articles to e-book formats for offline reading on e-readers.$q$, $q$Native and third-party clients extend the core web app: a native iOS app is available on the App Store, and an Android client is distributed through F-Droid, giving users mobile access to their self-hosted library alongside the browser extension used to save links.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('64003bd2-5181-45f3-8722-b827c604e9d2', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Readeck itself is free and open source; the only cost is the infrastructure needed to self-host it, such as a home server, NAS or small VPS. The project has announced plans to launch a paid, company-hosted tier in 2026 for users who prefer a managed instance, but as of now there is no official hosted SaaS product.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('64003bd2-5181-45f3-8722-b827c604e9d2', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('64003bd2-5181-45f3-8722-b827c604e9d2', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b8dd75e-cb27-4973-af45-0de6a657268d', $q$Centralized article inbox$q$, $q$Aggregates articles from multiple sources into one unified reading interface.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b8dd75e-cb27-4973-af45-0de6a657268d', $q$Incoming and outgoing webhooks$q$, $q$Connect RSS, Pocket, Wallabag, Shaarli and S3 buckets to automate how content flows in and out of Readflow.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b8dd75e-cb27-4973-af45-0de6a657268d', $q$Offline export formats$q$, $q$Export saved articles as HTML, PDF, EPUB or ZIP for offline reading.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b8dd75e-cb27-4973-af45-0de6a657268d', $q$Progressive Web App support$q$, $q$Provides an app-like experience on both desktop and mobile without a native app store listing.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b8dd75e-cb27-4973-af45-0de6a657268d', $q$Push notifications$q$, $q$Get notified when new articles are pushed into your reading queue.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b8dd75e-cb27-4973-af45-0de6a657268d', $q$Ad-free and tracker-free$q$, $q$Deliberately excludes ads and trackers from the reading experience.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b8dd75e-cb27-4973-af45-0de6a657268d', $q$CLI and MCP server$q$, $q$Includes the readflow-ctl command-line tool plus an MCP server for AI assistant automation.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b8dd75e-cb27-4973-af45-0de6a657268d', $q$Multiple self-hosting options$q$, $q$Deploy via Go binary, Docker, or Docker Compose, backed by a PostgreSQL database.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b8dd75e-cb27-4973-af45-0de6a657268d', $q$Completely free and open source under AGPLv3$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b8dd75e-cb27-4973-af45-0de6a657268d', $q$Flexible webhook system for connecting to RSS, Pocket, Wallabag and more$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b8dd75e-cb27-4973-af45-0de6a657268d', $q$Multiple offline export formats including EPUB and PDF$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b8dd75e-cb27-4973-af45-0de6a657268d', $q$Progressive Web App gives a consistent cross-device experience$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b8dd75e-cb27-4973-af45-0de6a657268d', $q$Includes CLI and MCP server for automation and AI integration$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b8dd75e-cb27-4973-af45-0de6a657268d', $q$Requires self-hosting knowledge, including PostgreSQL database setup$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b8dd75e-cb27-4973-af45-0de6a657268d', $q$Development pace has slowed, with the latest release dating to March 2024$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b8dd75e-cb27-4973-af45-0de6a657268d', $q$No official hosted SaaS version or vendor support$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b8dd75e-cb27-4973-af45-0de6a657268d', $q$Smaller community (under 500 GitHub stars) than mainstream alternatives$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b8dd75e-cb27-4973-af45-0de6a657268d', $q$No native mobile apps, relying instead on the PWA experience$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b8dd75e-cb27-4973-af45-0de6a657268d', $q$Is Readflow free?$q$, $q$Yes, Readflow is free and open source under the AGPLv3 license, with no paid tiers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b8dd75e-cb27-4973-af45-0de6a657268d', $q$Who created Readflow?$q$, $q$Readflow is created and maintained by developer Nicolas Carlier, with development dating back to 2019.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b8dd75e-cb27-4973-af45-0de6a657268d', $q$What database does Readflow require?$q$, $q$Readflow requires a PostgreSQL database for persistence alongside its Go backend.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b8dd75e-cb27-4973-af45-0de6a657268d', $q$Can Readflow connect to other read-it-later services?$q$, $q$Yes, its webhook system supports integrations with RSS, Pocket, Wallabag, Shaarli and S3-compatible storage.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b8dd75e-cb27-4973-af45-0de6a657268d', $q$Does Readflow have a mobile app?$q$, $q$There is no native mobile app; instead, Readflow is delivered as a Progressive Web App for mobile and desktop use.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b8dd75e-cb27-4973-af45-0de6a657268d', $q$What export formats does Readflow support?$q$, $q$Saved articles can be exported offline as HTML, PDF, EPUB or ZIP files.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b8dd75e-cb27-4973-af45-0de6a657268d', $q$How do I self-host Readflow?$q$, $q$You can run the Go binary directly, use a Docker container, or deploy via Docker Compose.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b8dd75e-cb27-4973-af45-0de6a657268d', $q$Does Readflow support automation or AI tools?$q$, $q$Yes, it ships with a readflow-ctl CLI and an MCP server that lets AI assistants interact with your instance.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6b8dd75e-cb27-4973-af45-0de6a657268d', $q$Personal news aggregation$q$, $q$Pull articles from RSS feeds and other sources into a single, ad-free reading queue.$q$, $q$Individual readers and news enthusiasts$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6b8dd75e-cb27-4973-af45-0de6a657268d', $q$Automated content pipelines$q$, $q$Use incoming and outgoing webhooks to route saved articles to storage, other apps or custom scripts.$q$, $q$Self-hosters and automation-focused developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6b8dd75e-cb27-4973-af45-0de6a657268d', $q$Offline reading archives$q$, $q$Export saved content as EPUB, PDF or HTML for offline reading on e-readers or during travel.$q$, $q$Researchers and frequent travelers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6b8dd75e-cb27-4973-af45-0de6a657268d', $q$Self-Hosted$q$, $q$$0$q$, $q$Free forever (open source)$q$, NULL, $q$["Unlimited article saves and webhooks","HTML, PDF, EPUB and ZIP export","Progressive Web App access","CLI and MCP server included","Community support via GitHub"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6b8dd75e-cb27-4973-af45-0de6a657268d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Readflow is an open-source, self-hosted news-reading and read-it-later platform created by developer Nicolas Carlier, with development on GitHub dating back to April 2019. It is licensed under AGPLv3 and built on a Go backend with a React/TypeScript frontend and a GraphQL API.$q$, $q$The tool centralizes article reading from multiple sources into a single interface and is aimed at self-hosters who want a customizable, webhook-driven alternative to commercial read-it-later services like Pocket.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6b8dd75e-cb27-4973-af45-0de6a657268d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Readflow's incoming and outgoing webhook system connects it to RSS feeds, Pocket, Wallabag, Shaarli and S3-compatible storage, enabling flexible automation pipelines for how content enters and leaves the platform. Saved articles can be exported offline as HTML, PDF, EPUB or ZIP files.$q$, $q$The app is delivered as a Progressive Web App for a consistent mobile and desktop experience, supports push notifications for new articles, and includes a companion CLI (readflow-ctl) plus an MCP server for AI assistant integration.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6b8dd75e-cb27-4973-af45-0de6a657268d', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Readflow is completely free and open source; there is no company or hosted SaaS offering behind it. Users self-host the Go binary, Docker container, or Docker Compose stack on their own infrastructure, requiring a PostgreSQL database.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6b8dd75e-cb27-4973-af45-0de6a657268d', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6b8dd75e-cb27-4973-af45-0de6a657268d', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('889a35b0-763a-4ca4-86bc-b657c47e2c33', $q$Interactive API reference$q$, $q$Developers can execute live API calls and see real responses directly inside the documentation.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('889a35b0-763a-4ca4-86bc-b657c47e2c33', $q$Usage analytics$q$, $q$Tracks which endpoints are tested, where developers get stuck, and which docs sections drive engagement.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('889a35b0-763a-4ca4-86bc-b657c47e2c33', $q$Branching and review workflows$q$, $q$Teams can branch documentation changes and route them through review before publishing, similar to a code review flow.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('889a35b0-763a-4ca4-86bc-b657c47e2c33', $q$Custom MDX and CSS support$q$, $q$Extend documentation pages with custom MDX components and CSS/HTML for fully branded experiences.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('889a35b0-763a-4ca4-86bc-b657c47e2c33', $q$AI writing and linting tools$q$, $q$Includes an AI writing agent (Owlbert), AI linter, and GitHub-based AI writer to help produce and maintain docs.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('889a35b0-763a-4ca4-86bc-b657c47e2c33', $q$Changelog, forum and landing page modules$q$, $q$Built-in modules for publishing changelogs, hosting developer forums and building a docs landing page.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('889a35b0-763a-4ca4-86bc-b657c47e2c33', $q$SSO, audit logs and access controls$q$, $q$Enterprise-grade security features including SSO/OAuth, audit logs and granular user roles.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('889a35b0-763a-4ca4-86bc-b657c47e2c33', $q$Multi-project management$q$, $q$Enterprise customers can manage documentation for multiple products or APIs from one account.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('889a35b0-763a-4ca4-86bc-b657c47e2c33', $q$Live, interactive API testing embedded directly in the documentation$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('889a35b0-763a-4ca4-86bc-b657c47e2c33', $q$Detailed analytics on developer engagement with the docs$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('889a35b0-763a-4ca4-86bc-b657c47e2c33', $q$Trusted by well-known enterprises such as Microsoft and Akamai$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('889a35b0-763a-4ca4-86bc-b657c47e2c33', $q$Free Starter tier available for smaller projects$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('889a35b0-763a-4ca4-86bc-b657c47e2c33', $q$Extensive AI tooling for writing, linting and auditing docs$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('889a35b0-763a-4ca4-86bc-b657c47e2c33', $q$Paid plans are billed annually, which can be a barrier for smaller teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('889a35b0-763a-4ca4-86bc-b657c47e2c33', $q$Pro and Enterprise pricing is significantly higher than many documentation competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('889a35b0-763a-4ca4-86bc-b657c47e2c33', $q$Enterprise pricing starts at $3,000+/month and requires a custom contract$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('889a35b0-763a-4ca4-86bc-b657c47e2c33', $q$Ask AI is a separate paid add-on rather than included by default on lower tiers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('889a35b0-763a-4ca4-86bc-b657c47e2c33', $q$Full branding removal requires an upgrade from the free Starter plan$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('889a35b0-763a-4ca4-86bc-b657c47e2c33', $q$How much does ReadMe cost?$q$, $q$ReadMe offers a free Starter plan, a Pro plan at $250/month billed annually, and Enterprise pricing starting at $3,000+/month on annual contracts.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('889a35b0-763a-4ca4-86bc-b657c47e2c33', $q$When was ReadMe founded?$q$, $q$ReadMe traces its origins to 2014 and launched publicly through Y Combinator's Winter 2015 batch, founded by Gregory Koberger.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('889a35b0-763a-4ca4-86bc-b657c47e2c33', $q$Where is ReadMe headquartered?$q$, $q$ReadMe is headquartered in San Francisco, California.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('889a35b0-763a-4ca4-86bc-b657c47e2c33', $q$Does ReadMe offer a free plan?$q$, $q$Yes, the Starter plan is free and includes the interactive API reference, usage metrics and basic AI features.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('889a35b0-763a-4ca4-86bc-b657c47e2c33', $q$What is Ask AI on ReadMe?$q$, $q$Ask AI is an AI-assistant add-on available across ReadMe plans for an additional $150/month, with a lighter version included on Pro.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('889a35b0-763a-4ca4-86bc-b657c47e2c33', $q$Which companies use ReadMe?$q$, $q$ReadMe is used by more than 4,000 companies, including large enterprises like Microsoft and Akamai.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('889a35b0-763a-4ca4-86bc-b657c47e2c33', $q$Does ReadMe support single sign-on?$q$, $q$SSO and OAuth support are available on the Enterprise plan.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('889a35b0-763a-4ca4-86bc-b657c47e2c33', $q$Can I remove ReadMe branding from my docs?$q$, $q$Branding removal is available starting on the Enterprise plan, not on the free Starter tier.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('889a35b0-763a-4ca4-86bc-b657c47e2c33', $q$API-first product documentation$q$, $q$Publish interactive, testable documentation for a public or partner-facing API to speed up developer integration.$q$, $q$API-first SaaS and platform companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('889a35b0-763a-4ca4-86bc-b657c47e2c33', $q$Developer experience and analytics$q$, $q$Track how developers interact with API docs to identify friction points and prioritize documentation fixes.$q$, $q$Developer experience and DevRel teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('889a35b0-763a-4ca4-86bc-b657c47e2c33', $q$Enterprise multi-product documentation$q$, $q$Manage documentation for multiple APIs or products under one account with SSO, audit logs and access controls.$q$, $q$Enterprise engineering and security teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('889a35b0-763a-4ca4-86bc-b657c47e2c33', $q$Starter$q$, $q$$0$q$, $q$Free$q$, NULL, $q$["Custom domain","Bi-directional sync","Interactive API reference","Usage metrics","Markdown editor and customizable themes","Basic AI features (AI Dropdown, LLMs.txt, MCP Server)"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('889a35b0-763a-4ca4-86bc-b657c47e2c33', $q$Pro$q$, $q$$250/month$q$, $q$Annual billing$q$, NULL, $q$["All Starter features","Team invitations","Branching and reviews","Private documentation","Landing page, changelog and forum modules","Custom MDX components and CSS/HTML support","Ask AI Lite, Owlbert AI agent, AI linter, GitHub AI writer"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('889a35b0-763a-4ca4-86bc-b657c47e2c33', $q$Enterprise$q$, $q$$3,000+/month$q$, $q$Annual contract$q$, NULL, $q$["All Pro features","Multi-project management","Removed ReadMe branding","User roles and access controls","Audit logs","SSO and OAuth support","Dedicated support and implementation services","Docs audit, private AI context, global lint rules"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('889a35b0-763a-4ca4-86bc-b657c47e2c33', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ReadMe is an interactive API documentation platform founded by Gregory Koberger, with company origins in 2014 and a public launch through Y Combinator's Winter 2015 batch. Headquartered in San Francisco, California, the company has raised roughly $10 million in funding, including a 2019 Series A led by Accel, and employs an estimated 70 to 83 people.$q$, $q$The platform is used by more than 4,000 companies, ranging from startups to large enterprises such as Microsoft and Akamai, to turn static API docs into interactive, testable reference hubs.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('889a35b0-763a-4ca4-86bc-b657c47e2c33', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$ReadMe's core differentiator is letting developers execute live API calls and see real responses directly inside the documentation, rather than switching to a separate API client or Postman collection. Built-in analytics show which endpoints get tested, where developers get stuck, and which sections drive the most engagement.$q$, $q$Higher tiers add collaboration features like branching and review workflows, private documentation, custom MDX and CSS support, changelog and forum modules, and a growing suite of AI tools including an AI writing agent, AI linter and documentation audits.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('889a35b0-763a-4ca4-86bc-b657c47e2c33', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$ReadMe offers a free Starter plan with the core interactive reference and basic AI features, a Pro plan at $250 per month billed annually that unlocks team collaboration and expanded AI tooling, and an Enterprise plan starting at $3,000 or more per month on annual contracts with SSO, audit logs and dedicated support.$q$, $q$An Ask AI add-on is available across all tiers for an additional $150 per month for teams that want the platform's fuller AI-assistant capabilities without moving to a higher plan.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', $q$No-code animation and interactions$q$, $q$Build scroll effects, transitions, overlays and multi-step interactions visually without writing code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', $q$Built-in font library$q$, $q$Access Google Fonts, Adobe Fonts and independent type foundries, plus support for custom font uploads.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', $q$Custom domain mapping$q$, $q$Connect one or more custom domains to published sites depending on plan tier.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', $q$Basic e-commerce$q$, $q$Sell up to a limited number of products directly from a Readymag site on entry-level plans.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', $q$Code export and iFrame embedding$q$, $q$Higher-tier plans allow exporting code or embedding published pages via iFrame for more technical workflows.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', $q$Multi-collaborator support$q$, $q$Invite collaborators to work on projects together, with collaborator limits increasing on higher tiers.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', $q$Public profile publishing$q$, $q$Publish multiple sites under one shared profile domain without mapping a custom domain to each.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', $q$Priority support on top tiers$q$, $q$The Advanced/Business plan includes priority customer support for larger teams and agencies.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', $q$Strong no-code animation and interaction tooling not commonly found in competitors$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', $q$Large built-in font library including Google Fonts and Adobe Fonts$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', $q$Free plan available with no credit card required$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', $q$Founder-owned and bootstrapped, suggesting stable, profitable operations$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', $q$Flexible for both simple portfolios and complex, animation-heavy sites$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', $q$Paid plans are needed for custom domains, limiting the free tier's practical use$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', $q$Freelancer and Business plans still cap collaborators and published-site domain mapping$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', $q$Less suited to complex e-commerce compared to dedicated platforms like Shopify$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', $q$Steeper learning curve for advanced animation features compared to simple template builders$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', $q$Enterprise pricing is not published and requires direct contact$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', $q$How much does Readymag cost?$q$, $q$Readymag has a free plan, then paid tiers starting at $14/month (Personal), $22/month (Freelancer) and $58.50/month (Advanced/Business), with an Enterprise plan available on request.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', $q$When was Readymag founded?$q$, $q$Readymag was founded in 2012 and launched publicly in 2013 by Anton Herasymenko, Diana Kasay and Kirill Danchenko.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', $q$Where is Readymag headquartered?$q$, $q$Readymag is headquartered in New York City, at 155 Water Street.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', $q$Is Readymag a coding tool?$q$, $q$No, Readymag is a no-code, browser-based design tool, though higher-tier plans allow exporting code for developers who want it.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', $q$Does Readymag support e-commerce?$q$, $q$Yes, the Personal plan supports basic e-commerce for up to 10 products, with higher limits on upper tiers.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', $q$Is Readymag venture-backed?$q$, $q$No, as of 2024 Readymag has bought out all external investors and is fully founder-owned and bootstrapped.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', $q$Can I use my own domain with Readymag?$q$, $q$Yes, paid plans support mapping one or more custom domains depending on the tier.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', $q$Does Readymag offer a discount for annual billing?$q$, $q$Yes, annual billing offers roughly a 10 percent discount compared to monthly billing.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', $q$Designer and agency portfolios$q$, $q$Build visually distinctive, animation-rich portfolio sites without hiring a developer.$q$, $q$Designers, studios and creative agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', $q$Freelance client website delivery$q$, $q$Host and publish multiple client websites from one account with mapped custom domains.$q$, $q$Freelance designers and consultants$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', $q$Digital publications and presentations$q$, $q$Create interactive online magazines, decks and campaign microsites with scroll-based storytelling.$q$, $q$Marketing teams and publishers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', $q$Free$q$, $q$$0$q$, $q$Free (no credit card required)$q$, NULL, $q$["Full editing tools","No custom domain","Readymag subdomain publishing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', $q$Personal$q$, $q$$14/month$q$, $q$Monthly (annual discount available)$q$, NULL, $q$["One custom domain on one site","SSL encryption","Analytics integrations","E-commerce for up to 10 products"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', $q$Freelancer$q$, $q$$22/month$q$, $q$Monthly (annual discount available)$q$, NULL, $q$["Publish 5 websites","Map custom domains to 3 sites","2 collaborators","25,000 project views per month","Public profile publishing"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', $q$Advanced (Business)$q$, $q$$58.50/month$q$, $q$Monthly (annual discount available)$q$, NULL, $q$["Unlimited published websites","10 custom domains","10 collaborators","Code export and iFrame embedding","Priority support"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', $q$Enterprise$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["Tailored limits for large organizations","Dedicated support","Custom contract terms"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Readymag is a browser-based, no-code design platform founded in 2012 by Anton Herasymenko, Diana Kasay and Kirill Danchenko, and launched publicly in 2013 as a tool for digital magazines before broadening into a general-purpose website and presentation design tool. The company is headquartered in New York City and employs roughly 50 people.$q$, $q$As of 2024, Readymag has bought out all external investors and operates as a fully founder-owned, bootstrapped company, positioning it as a design-forward, no-code alternative to platforms like Webflow or Squarespace with a particular emphasis on animation and freeform layout.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Readymag is best known for its animation and interaction tools, letting designers build scroll effects, transitions, overlays and multi-step interactions visually, without code. Higher-tier plans also support code export and iFrame embedding for teams that want more technical control.$q$, $q$The platform includes a built-in font library spanning Google Fonts, Adobe Fonts and independent type foundries, plus custom font uploads, giving designers significant typographic flexibility for building distinctive, on-brand pages.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Readymag offers a free plan with no credit card required, plus three main paid tiers: Personal at $14/month, Freelancer at $22/month and Advanced (Business) at $58.50/month, each unlocking more custom domains, collaborators and publishing limits. An Enterprise plan with custom pricing is also available.$q$, $q$All paid subscriptions can be billed monthly or annually, with annual billing offering roughly a 10 percent discount compared to paying month to month.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4251d844-33b1-400c-bb7b-088d475cef82', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('effcc65a-35ca-4139-bbe4-ff1e95fd6c80', $q$Cross-server Plex downloading$q$, $q$Connect multiple Plex accounts and servers and download accessible media into your own library.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('effcc65a-35ca-4139-bbe4-ff1e95fd6c80', $q$Dual library views$q$, $q$Browse content in either a poster grid or a detailed table layout, whichever fits your workflow.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('effcc65a-35ca-4139-bbe4-ff1e95fd6c80', $q$Advanced filtering and sorting$q$, $q$Filter and sort available media by genre, year, quality and other attributes before downloading.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('effcc65a-35ca-4139-bbe4-ff1e95fd6c80', $q$Multi-threaded downloads with auto-recovery$q$, $q$Multiple parallel download threads keep the queue moving, with automatic recovery from interrupted transfers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('effcc65a-35ca-4139-bbe4-ff1e95fd6c80', $q$Sonarr and Radarr integration$q$, $q$Acts as an indexer and download client so Sonarr and Radarr can queue items for Reaparr to process automatically.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('effcc65a-35ca-4139-bbe4-ff1e95fd6c80', $q$Per-item destination folders$q$, $q$Choose a specific destination folder for each downloaded item rather than a single fixed location.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('effcc65a-35ca-4139-bbe4-ff1e95fd6c80', $q$Cross-platform Docker deployment$q$, $q$Runs via Docker on Windows, Linux, macOS, Unraid and Synology, across both ARM and AMD architectures.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('effcc65a-35ca-4139-bbe4-ff1e95fd6c80', $q$Multi-language interface$q$, $q$Supports English, French, German and Polish, with additional languages planned.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('effcc65a-35ca-4139-bbe4-ff1e95fd6c80', $q$Completely free and open source under GPL-3.0$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('effcc65a-35ca-4139-bbe4-ff1e95fd6c80', $q$Integrates directly with Sonarr and Radarr as an indexer and download client$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('effcc65a-35ca-4139-bbe4-ff1e95fd6c80', $q$Multi-threaded downloads with automatic recovery from interruptions$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('effcc65a-35ca-4139-bbe4-ff1e95fd6c80', $q$Cross-platform support including NAS systems like Unraid and Synology$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('effcc65a-35ca-4139-bbe4-ff1e95fd6c80', $q$Active Discord community for user support$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('effcc65a-35ca-4139-bbe4-ff1e95fd6c80', $q$Requires access to Plex servers with media you are permitted to download from$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('effcc65a-35ca-4139-bbe4-ff1e95fd6c80', $q$Self-hosting via Docker requires some technical setup knowledge$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('effcc65a-35ca-4139-bbe4-ff1e95fd6c80', $q$No official company, SLA or paid support tier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('effcc65a-35ca-4139-bbe4-ff1e95fd6c80', $q$Smaller, newer project that previously had to rebrand due to a trademark dispute$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('effcc65a-35ca-4139-bbe4-ff1e95fd6c80', $q$Language support is currently limited to a handful of languages$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('effcc65a-35ca-4139-bbe4-ff1e95fd6c80', $q$Is Reaparr free to use?$q$, $q$Yes, Reaparr is completely free and open source under the GPL-3.0 license, supported by voluntary donations.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('effcc65a-35ca-4139-bbe4-ff1e95fd6c80', $q$Why is it called Reaparr instead of its original name?$q$, $q$The project renamed itself to Reaparr after receiving a trademark complaint from Plex Inc., choosing a name that echoes the *arr naming convention of tools like Sonarr and Radarr.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('effcc65a-35ca-4139-bbe4-ff1e95fd6c80', $q$Does Reaparr work with Sonarr and Radarr?$q$, $q$Yes, it can function as an indexer and download client so Sonarr and Radarr can queue items for Reaparr to download automatically.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('effcc65a-35ca-4139-bbe4-ff1e95fd6c80', $q$What platforms does Reaparr support?$q$, $q$Reaparr runs via Docker on Windows, Linux, macOS, Unraid and Synology, supporting both ARM and AMD hardware.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('effcc65a-35ca-4139-bbe4-ff1e95fd6c80', $q$What languages does Reaparr support?$q$, $q$The interface currently supports English, French, German and Polish, with more languages planned.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('effcc65a-35ca-4139-bbe4-ff1e95fd6c80', $q$Does Reaparr have a paid tier?$q$, $q$No, Reaparr has no pricing tiers; it is entirely free and sustained through user donations.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('effcc65a-35ca-4139-bbe4-ff1e95fd6c80', $q$How does Reaparr handle interrupted downloads?$q$, $q$It automatically recovers from download interruptions rather than requiring users to manually restart the transfer.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('effcc65a-35ca-4139-bbe4-ff1e95fd6c80', $q$Where can I get support for Reaparr?$q$, $q$Support is available through an active Discord community, GitHub issues and the project's documentation and FAQ pages.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('effcc65a-35ca-4139-bbe4-ff1e95fd6c80', $q$Consolidating media across Plex servers$q$, $q$Pull media you have access to from friends' or family's Plex servers into your own personal library.$q$, $q$Home media server enthusiasts$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('effcc65a-35ca-4139-bbe4-ff1e95fd6c80', $q$Automated Sonarr/Radarr workflows$q$, $q$Use Reaparr as an indexer and download client so Sonarr and Radarr queues are fulfilled automatically.$q$, $q$Self-hosted media automation users$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('effcc65a-35ca-4139-bbe4-ff1e95fd6c80', $q$NAS-based media management$q$, $q$Run Reaparr on Unraid or Synology alongside other self-hosted apps to centralize media downloading.$q$, $q$NAS owners and home-lab operators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('effcc65a-35ca-4139-bbe4-ff1e95fd6c80', $q$Self-Hosted$q$, $q$$0$q$, $q$Free forever (open source, donation-supported)$q$, NULL, $q$["Unlimited Plex account and server connections","Sonarr and Radarr integration","Multi-threaded downloads with auto-recovery","Poster grid and table library views","Cross-platform Docker deployment"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('effcc65a-35ca-4139-bbe4-ff1e95fd6c80', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Reaparr is a free, open-source, self-hosted Plex downloader that lets users pull media from any accessible Plex server into their own library. The project was previously distributed under a different, Plex-referencing name before a trademark complaint from Plex Inc. prompted a rename to Reaparr, chosen to echo the naming convention of the broader *arr media-tooling ecosystem such as Sonarr and Radarr.$q$, $q$The project is licensed under GPL-3.0, hosted on GitHub under the Reaparr organization, and distributed as Docker images for cross-platform deployment on Windows, Linux, macOS, Unraid and Synology systems across both ARM and AMD hardware.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('effcc65a-35ca-4139-bbe4-ff1e95fd6c80', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Reaparr connects multiple Plex accounts and servers, letting users browse and download accessible media through a poster-grid or table view with filtering and sorting by genre, year and quality, and per-item destination folder selection. Downloads run across multiple parallel threads with automatic recovery from interruptions.$q$, $q$Beyond standalone downloading, Reaparr can act as an indexer and download client inside Sonarr and Radarr, letting those tools queue items for Reaparr to fetch automatically, functioning as an alternative to traditional torrent or Usenet indexers within that workflow.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('effcc65a-35ca-4139-bbe4-ff1e95fd6c80', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Reaparr is entirely free and open source, with no paid tiers or commercial entity behind it. The project is sustained through voluntary donations that fund ongoing development, hosting and documentation, and users self-host the application via Docker on their own hardware.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('effcc65a-35ca-4139-bbe4-ff1e95fd6c80', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('effcc65a-35ca-4139-bbe4-ff1e95fd6c80', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('16d7a916-ff92-4379-8cb9-06913256e22d', $q$Chrome sourcing extension$q$, $q$Pull candidate profiles and data directly from LinkedIn and other websites into Recruit CRM while browsing.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('16d7a916-ff92-4379-8cb9-06913256e22d', $q$AI resume parser$q$, $q$Automatically extracts structured candidate data from uploaded resumes to speed up data entry.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('16d7a916-ff92-4379-8cb9-06913256e22d', $q$GPT integration$q$, $q$Uses GPT-based AI to help generate job descriptions, candidate outreach messages and other recruiting content.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('16d7a916-ff92-4379-8cb9-06913256e22d', $q$Deal and hiring pipelines$q$, $q$Track both client business deals and candidate hiring stages in configurable pipeline views.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('16d7a916-ff92-4379-8cb9-06913256e22d', $q$Integrated mailbox and calling$q$, $q$Send and receive email plus make and record phone calls directly within the platform.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('16d7a916-ff92-4379-8cb9-06913256e22d', $q$Automated email sequencing$q$, $q$Set up multi-step, automated email sequences to nurture candidates and clients over time (Business plan and up).$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('16d7a916-ff92-4379-8cb9-06913256e22d', $q$Executive search report generator$q$, $q$Produce client-ready executive search reports directly from candidate and search data (Business plan and up).$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('16d7a916-ff92-4379-8cb9-06913256e22d', $q$Workflow automation and data enrichment$q$, $q$Automate recurring tasks and enrich contact records with phone and email data on the Enterprise plan.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('16d7a916-ff92-4379-8cb9-06913256e22d', $q$Purpose-built specifically for recruitment and staffing agency workflows$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('16d7a916-ff92-4379-8cb9-06913256e22d', $q$Combines ATS, CRM deal pipelines and communication tools in one platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('16d7a916-ff92-4379-8cb9-06913256e22d', $q$AI resume parsing and GPT integration speed up candidate processing$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('16d7a916-ff92-4379-8cb9-06913256e22d', $q$Scales from small agencies (Pro) to large enterprise search firms$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('16d7a916-ff92-4379-8cb9-06913256e22d', $q$Free trial available before committing to a paid subscription$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('16d7a916-ff92-4379-8cb9-06913256e22d', $q$Per-user pricing can get expensive quickly for larger agency teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('16d7a916-ff92-4379-8cb9-06913256e22d', $q$Entry-level Pro plan limits hiring pipelines and candidate matches$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('16d7a916-ff92-4379-8cb9-06913256e22d', $q$Enterprise pricing is not published and requires a sales demo$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('16d7a916-ff92-4379-8cb9-06913256e22d', $q$Some advanced features like SSO and audit logs are gated behind the Business tier$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('16d7a916-ff92-4379-8cb9-06913256e22d', $q$Data enrichment and workflow automation credits are capped even on Enterprise$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('16d7a916-ff92-4379-8cb9-06913256e22d', $q$How much does Recruit CRM cost?$q$, $q$Recruit CRM starts at $85/user/month billed annually (or $100/user/month monthly) for the Pro plan, with Business and Enterprise tiers priced higher per user.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('16d7a916-ff92-4379-8cb9-06913256e22d', $q$When was Recruit CRM founded?$q$, $q$Recruit CRM was founded in 2017.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('16d7a916-ff92-4379-8cb9-06913256e22d', $q$Where is Recruit CRM headquartered?$q$, $q$Recruit CRM maintains dual headquarters in Norwood, New Jersey, USA and Pune, India, with a fully remote team.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('16d7a916-ff92-4379-8cb9-06913256e22d', $q$Who is Recruit CRM built for?$q$, $q$It is built specifically for recruitment and staffing agencies and executive search firms, rather than generic internal corporate recruiting teams.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('16d7a916-ff92-4379-8cb9-06913256e22d', $q$Does Recruit CRM include AI features?$q$, $q$Yes, it includes an AI resume parser and GPT integration for generating recruiting content, with advanced analytics on higher tiers.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('16d7a916-ff92-4379-8cb9-06913256e22d', $q$Is there a free trial for Recruit CRM?$q$, $q$Yes, Recruit CRM offers a free trial before requiring a paid subscription.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('16d7a916-ff92-4379-8cb9-06913256e22d', $q$What is included in the Business plan that Pro lacks?$q$, $q$Business adds automated email sequencing, bulk texting, an executive search report generator, resume formatting, custom roles/teams, SSO and audit logs, among other features.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('16d7a916-ff92-4379-8cb9-06913256e22d', $q$Does Recruit CRM integrate with LinkedIn?$q$, $q$Yes, it includes a Chrome sourcing extension for pulling candidate data from LinkedIn, plus LinkedIn messaging integration on the Enterprise plan.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('16d7a916-ff92-4379-8cb9-06913256e22d', $q$Recruitment agency candidate pipeline management$q$, $q$Track candidates through hiring pipelines from sourcing to placement, alongside client deal pipelines.$q$, $q$Recruitment and staffing agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('16d7a916-ff92-4379-8cb9-06913256e22d', $q$Executive search reporting$q$, $q$Generate client-ready executive search reports and format resumes for high-touch retained search engagements.$q$, $q$Executive search and headhunting firms$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('16d7a916-ff92-4379-8cb9-06913256e22d', $q$Scaling multi-recruiter teams$q$, $q$Coordinate custom roles, workflow automation and data enrichment across larger recruiting teams.$q$, $q$Growing staffing firms and enterprise recruiting teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('16d7a916-ff92-4379-8cb9-06913256e22d', $q$Pro$q$, $q$$85/user/month (annual) or $100/user/month (monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["Chrome sourcing extension","AI resume parser","GPT integration","Unlimited email templates","Integrated mailbox","Deal pipelines","Phone calling and recording","Complete reporting suite","Unlimited open jobs","1 hiring pipeline, up to 2 candidate matches","Up to 15 custom fields"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('16d7a916-ff92-4379-8cb9-06913256e22d', $q$Business$q$, $q$Approximately $125/user/month (annual) or $150/user/month (monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["All Pro features","Automated email sequencing","Bulk texting","Executive Search Report Generator","Resume formatting","Custom roles and teams","Multiple hiring pipelines","IP whitelisting and audit logs","Single sign-on (SSO)","Up to 50 candidate matches, 150 custom fields","Branding removal and open API access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('16d7a916-ff92-4379-8cb9-06913256e22d', $q$Enterprise$q$, $q$From approximately $165/user/month (custom demo pricing)$q$, $q$Custom / annual$q$, NULL, $q$["All Business features","Workflow automation (1,000 tasks/user/month)","Advanced analytics","LinkedIn messaging integration","Data enrichment (500 credits/user/month)","Calling and texting credits","Unlimited jobs via Recruit Craft","Job multiposting (10 jobs/user/month)","Dedicated account manager"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('16d7a916-ff92-4379-8cb9-06913256e22d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Recruit CRM is an applicant tracking system and CRM built specifically for recruitment agencies and executive search firms, founded in 2017. It maintains dual headquarters in Norwood, New Jersey and Pune, India, operating as a fully remote company with roughly 365 employees serving customers in more than 80 countries.$q$, $q$The platform is positioned as an AI-first recruiting tool purpose-built for agency workflows, combining candidate sourcing, an ATS, CRM-style deal pipelines and communication tools in one system, distinguishing it from generic corporate ATS software.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('16d7a916-ff92-4379-8cb9-06913256e22d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core features include a Chrome sourcing extension, an AI resume parser, GPT-based integrations for content generation, deal pipelines alongside candidate pipelines, an integrated mailbox, and built-in phone calling with call recording. Higher tiers add automated email sequencing, bulk texting, executive search report generation and resume formatting.$q$, $q$Enterprise-level customers get workflow automation, advanced analytics, LinkedIn messaging integration, contact data enrichment credits, job multiposting and a dedicated account manager, reflecting the platform's focus on scaling larger staffing operations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('16d7a916-ff92-4379-8cb9-06913256e22d', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Recruit CRM prices per user across three tiers: Pro starts at $85/user/month billed annually (or $100/user/month monthly), Business starts at roughly $125/user/month annually, and Enterprise starts at roughly $165/user/month with custom demo-based pricing.$q$, $q$All plans offer a discount for annual billing compared to monthly billing, and a free trial is available before subscribing to any paid tier.$q$]::text[], 2);
